@dataclass
class VideoParams:
    """Video generation params."""
    video_subject: str = ""
    video_script: str = ""
    video_keywords: str = ""
    video_terms: Optional[List[str]] = None
    video_aspect: str = "9:16"
    video_concat_mode: str = "random"
    video_transition_mode: Optional[str] = None
    video_clip_duration: int = 5
    video_count: int = 1
    video_source: str = "pexels"
    video_materials: Optional[List[str]] = None
    custom_audio_file: Optional[str] = None
    video_language: str = ""
    
    voice_name: str = "zh-CN-XiaoxiaoNeural-Female"
    voice_volume: float = 1.0
    voice_rate: float = 1.0
