def _fallback_terms(video_subject: str, video_script: str, amount: int = 5) -> List[str]:
    """Fallback terms extracted from ascii words in subject/script."""
    import re
    text = f"{video_subject}\n{video_script}"
    words = re.findall(r"[A-Za-z][A-Za-z0-9-]+", text)
    seen = set()
    terms = []
    for w in words:
        wl = w.lower()
        if wl in seen:
            continue
        seen.add(wl)
        terms.append(wl)
        if len(terms) >= amount:
            break
    if terms:
        return terms
    subject = (video_subject or "").strip()
    return [subject] if subject else []


def _parse_user_terms(raw: object, limit: int = 8) -> List[str]:
    if raw is None:
        return []
    if isinstance(raw, list):
        src = [str(x).strip() for x in raw if str(x).strip()]
    else:
        text = str(raw).strip()
        if not text:
            return []
        src = [x.strip() for x in re.split(r"[,，;；|/\n\r\t]+", text) if x.strip()]
    out: List[str] = []
    seen = set()
    for t in src:
        k = t.lower()
        if k in seen:
            continue
        seen.add(k)
        out.append(t)
        if len(out) >= max(1, int(limit)):
            break
    return out


def _merge_terms(primary: List[str], secondary: List[str], limit: int = 8) -> List[str]:
    out: List[str] = []
    seen = set()
    for arr in (primary or [], secondary or []):
        for t in arr:
            ts = str(t).strip()
            if not ts:
                continue
            k = ts.lower()
            if k in seen:
                continue
            seen.add(k)
            out.append(ts)
            if len(out) >= max(1, int(limit)):
                return out
    return out


