            audio_duration = float(get_audio_duration(audio_file) or 0.0)
            try:
                raw_total = float((tts_timestamps[-1] or {}).get("end") or 0.0)
            except Exception:
                raw_total = 0.0
            scale = 1.0
            # Scale timeline to real audio duration to avoid tail overflow.
            if audio_duration > 0 and raw_total > 0:
                scale = audio_duration / raw_total
            lines: List[str] = []
            idx = 1
            prev_end = 0.0

            for ts in tts_timestamps:
                if not isinstance(ts, dict):
                    continue
                text = str(ts.get("text", "") or "").strip()
                if not text:
                    continue

                try:
                    start = float(ts.get("start", prev_end) or prev_end) * scale
                except Exception:
                    start = prev_end
                try:
                    end = float(ts.get("end", start + 0.3) or (start + 0.3)) * scale
                except Exception:
                    end = start + 0.3

                # Keep monotonic timeline and avoid zero-length tail subtitle.
                start = max(0.0, start, prev_end)
                min_dur = 0.35
                if end <= start:
                    end = start + min_dur
                # Clamp to audio duration to prevent off-end subtitles.
                if audio_duration > 0:
                    start = min(start, max(0.0, audio_duration - min_dur))
                    end = min(audio_duration, max(end, start + min_dur))
                prev_end = end

                lines.append(str(idx))
                lines.append(f"{format_srt_time(start)} --> {format_srt_time(end)}")
                lines.append(text)
                lines.append("")
                idx += 1

            if not lines:
                raise RuntimeError("TTS timestamps are empty, cannot generate subtitles")

            # Keep a trailing blank block separator so subtitle parsers
            # reliably include the last cue.
            srt_text = "\n".join(lines).rstrip() + "\n\n"
            os.makedirs(os.path.dirname(subtitle_path), exist_ok=True)
